import type { ComponentType } from "react";

// The UI primitives are generated JavaScript wrappers around Radix and native
// elements. Their inferred JS types expose only `ref`, which makes every valid
// JSX prop look like an error. Keep this untyped boundary explicit so the
// application and domain code remain type-checked instead of disabling JS
// checking for the whole project.
declare const DefaultComponent: ComponentType<any>;
export default DefaultComponent;

